import React, { useState, useEffect } from "react";
import axios from "axios";

const SearchBar = ({ onSearch, onCategoryChange }) => {

  const userId = "user123"; // 🔥 same as backend

  const [categories, setCategories] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");

  // 🔹 FETCH CATEGORIES FROM DB
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get(
          `http://localhost:5001/api/categories?userId=${userId}`
        );
        setCategories(res.data);
      } catch (err) {
        console.error("CATEGORY FETCH ERROR 👉", err);
      }
    };

    fetchCategories();
  }, []);

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    onSearch && onSearch(value);
  };

  const handleCategory = (value) => {
    setSelectedCategory(value);
    onCategoryChange && onCategoryChange(value);
  };

  return (
    <div className="w-grid md:grid-cols-2 gap-6 p-6">

      {/* 🔍 Search + 📂 Dropdown */}
      <div className="flex gap-3">

        {/* Search */}
        <input
          type="text"
          placeholder="Search tasks..."
          value={search}
          onChange={handleSearch}
          className="flex-1 px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-white/30"
        />

        {/* Dropdown */}
        <select
          value={selectedCategory}
          onChange={(e) => handleCategory(e.target.value)}
          className="px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white focus:outline-none focus:ring-2 focus:ring-white/30"
        >
          <option value="" disabled className="text-black">
            Select Category
          </option>

          {/* 🔥 DB categories */}
          {categories.map((cat) => (
            <option key={cat._id} value={cat.name} className="text-black">
              {cat.name}
            </option>
          ))}
        </select>

      </div>

    </div>
  );
};

export default SearchBar;
